import{_ as a,a as t}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as i,o as l,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"WebDAV-доступ до сайту (Beta)","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/Safety/webdav-site-access.md","filePath":"uk-UA/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),n={name:"uk-UA/Safety/webdav-site-access.md"};function o(s,e,h,p,b,c){return l(),d("div",null,[...e[0]||(e[0]=[r('<h1 id="webdav-доступ-до-саиту-beta" tabindex="-1">WebDAV-доступ до сайту (Beta) <a class="header-anchor" href="#webdav-доступ-до-саиту-beta" aria-label="Permalink to &quot;WebDAV-доступ до сайту (Beta)&quot;">​</a></h1><p>Налаштування WebDAV у Security Settings відкриває ваш сайт ImgBed як WebDAV endpoint.</p><p>Після ввімкнення можна використовувати Windows, macOS, мобільні файлові менеджери або будь-який WebDAV-сумісний клієнт, щоб переглядати, завантажувати, видаляти й керувати файлами ImgBed як віддаленою папкою.</p><p>Це вхід WebDAV-доступу саме до сайту. Він відрізняється від WebDAV storage channel у налаштуваннях завантаження. Канал завантаження зберігає файли в сторонньому WebDAV-сервісі. Це налаштування дозволяє вашому сайту ImgBed надавати WebDAV-доступ клієнтам.</p><h2 id="де-це-налаштовується" tabindex="-1">Де це налаштовується <a class="header-anchor" href="#де-це-налаштовується" aria-label="Permalink to &quot;Де це налаштовується&quot;">​</a></h2><p>Відкрийте адмін-панель і перейдіть до:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; WebDAV</span></span></code></pre></div><p>Доступні налаштування:</p><ul><li>Enable</li><li>Username</li><li>Password</li><li>Image loading mode</li><li>Default channel</li></ul><h2 id="що-робить-ця-функція" tabindex="-1">Що робить ця функція <a class="header-anchor" href="#що-робить-ця-функція" aria-label="Permalink to &quot;Що робить ця функція&quot;">​</a></h2><p>Після ввімкнення WebDAV ImgBed надає фіксований URL доступу:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/dav</span></span></code></pre></div><p>Використовуйте цей URL для підключення до файлової директорії ImgBed.</p><p>Корисні сценарії:</p><ul><li>переглядати файли ImgBed напряму з файлового менеджера комп&#39;ютера;</li><li>перетягувати зображення в WebDAV-папку для завантаження;</li><li>упорядковувати папки ImgBed з локального файлового менеджера;</li><li>використовувати WebDAV-сумісне ПЗ для синхронізації або керування зображеннями;</li><li>отримувати доступ до вмісту ImgBed без відкриття адмін-панелі.</li></ul><h2 id="налаштування" tabindex="-1">Налаштування <a class="header-anchor" href="#налаштування" aria-label="Permalink to &quot;Налаштування&quot;">​</a></h2><h3 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h3><p>Увімкнення WebDAV endpoint.</p><p>Коли вимкнено, клієнти не можуть підключитися через WebDAV.</p><h3 id="username-і-password" tabindex="-1">Username і Password <a class="header-anchor" href="#username-і-password" aria-label="Permalink to &quot;Username і Password&quot;">​</a></h3><p>Ці облікові дані використовуються WebDAV-клієнтами під час підключення.</p><p>Використовуйте окремі WebDAV username і password. Не використовуйте повторно admin password або upload password.</p><p>Якщо username або password порожні, WebDAV-клієнти не зможуть підключатися коректно.</p><h3 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h3><p>Image loading mode визначає, який URL зображення WebDAV-клієнти віддають перевагу під час читання зображень.</p><p>Поширені варіанти:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Опис</th></tr></thead><tbody><tr><td>Smart loading</td><td>ImgBed вибирає на основі контексту. Рекомендовано для звичайного використання.</td></tr><tr><td>Original</td><td>Перевага оригінальним зображенням.</td></tr><tr><td>Thumbnail</td><td>Перевага мініатюрам. Корисно для швидкого попереднього перегляду.</td></tr></tbody></table><p>Якщо не впевнені, залиште <code>Smart loading</code>.</p><h3 id="default-channel" tabindex="-1">Default Channel <a class="header-anchor" href="#default-channel" aria-label="Permalink to &quot;Default Channel&quot;">​</a></h3><p>Default channel використовується для WebDAV-завантажень.</p><p>Коли ви копіюєте файли в WebDAV-директорію з Windows або іншого клієнта, ImgBed завантажує їх через вибраний default upload channel.</p><p>Якщо default channel не вибраний, перегляд може працювати, але завантаження може падати.</p><h2 id="доступ-до-webdav-у-windows-11" tabindex="-1">Доступ до WebDAV у Windows 11 <a class="header-anchor" href="#доступ-до-webdav-у-windows-11" aria-label="Permalink to &quot;Доступ до WebDAV у Windows 11&quot;">​</a></h2><p>Windows 11 може додати WebDAV як network location.</p><ol><li>Відкрийте <code>This PC</code>.</li><li>Виберіть <code>Add a network location</code>.</li><li>Введіть <code>https://your-domain.com/dav</code>.</li><li>Коли з&#39;явиться запит, введіть WebDAV username і password.</li><li>Завершіть майстер. Після цього WebDAV-директорію можна відкривати у File Explorer.</li></ol><p><img src="'+a+'" alt="Додавання WebDAV у Windows 11" loading="lazy"></p><p>Після додавання WebDAV-директорія з&#39;явиться у Windows File Explorer. Можна відкривати, копіювати й керувати файлами як у звичайній папці.</p><p><img src="'+t+'" alt="WebDAV у Windows" loading="lazy"></p><h2 id="підтримувані-операціі" tabindex="-1">Підтримувані операції <a class="header-anchor" href="#підтримувані-операціі" aria-label="Permalink to &quot;Підтримувані операції&quot;">​</a></h2><p>Після успішного WebDAV-підключення зазвичай можна:</p><ul><li>переглядати файли й папки;</li><li>завантажувати файли;</li><li>створювати папки;</li><li>перейменовувати файли або папки;</li><li>переміщувати файли;</li><li>видаляти файли.</li></ul><p>WebDAV найкраще підходить для щоденного доступу й невеликого керування файлами. Для великих переміщень, масових видалень або складної організації краще використовувати адмін-панель.</p><h2 id="login-device-management" tabindex="-1">Login Device Management <a class="header-anchor" href="#login-device-management" aria-label="Permalink to &quot;Login Device Management&quot;">​</a></h2><p>Успішні WebDAV-підключення також з&#39;являються у вкладці WebDAV в Login Device Management.</p><p>Там можна переглядати WebDAV-клієнти й за потреби примусово виводити старі пристрої офлайн.</p><p>Якщо змінити WebDAV username або password, старим клієнтам потрібно буде увійти знову.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="windows-постіино-запитує-username-і-password" tabindex="-1">Windows постійно запитує username і password <a class="header-anchor" href="#windows-постіино-запитує-username-і-password" aria-label="Permalink to &quot;Windows постійно запитує username і password&quot;">​</a></h3><p>Перевірте:</p><ul><li>URL має бути <code>https://your-domain.com/dav</code>.</li><li>Username і password збігаються з налаштуваннями WebDAV.</li><li>WebDAV увімкнений.</li><li>Сайт доступний через HTTPS.</li></ul><h3 id="перегляд-працює-але-завантаження-ні" tabindex="-1">Перегляд працює, але завантаження ні <a class="header-anchor" href="#перегляд-працює-але-завантаження-ні" aria-label="Permalink to &quot;Перегляд працює, але завантаження ні&quot;">​</a></h3><p>Перевірте <code>Default channel</code>.</p><p>Для WebDAV-завантажень потрібен default upload channel. Якщо його немає, він вимкнений або неправильно налаштований, завантаження можуть не працювати.</p><h3 id="швидкість-доступу-нестабільна" tabindex="-1">Швидкість доступу нестабільна <a class="header-anchor" href="#швидкість-доступу-нестабільна" aria-label="Permalink to &quot;Швидкість доступу нестабільна&quot;">​</a></h3><p>Продуктивність WebDAV залежить від клієнта, мережі, кількості файлів і default upload channel.</p><p>Якщо в директорії багато файлів, розкладіть їх по папках, а не тримайте надто багато файлів в одній директорії.</p><h2 id="рекомендаціі-з-безпеки" tabindex="-1">Рекомендації з безпеки <a class="header-anchor" href="#рекомендаціі-з-безпеки" aria-label="Permalink to &quot;Рекомендації з безпеки&quot;">​</a></h2><ul><li>Використовуйте HTTPS для WebDAV-доступу.</li><li>Встановіть надійний пароль.</li><li>Не передавайте WebDAV password людям, яким не довіряєте.</li><li>Вимикайте WebDAV, коли не користуєтеся ним.</li><li>Періодично очищайте невикористані WebDAV devices у Login Device Management.</li></ul><h2 id="розмір-фаилів-для-webdav-завантаження" tabindex="-1">Розмір файлів для WebDAV-завантаження <a class="header-anchor" href="#розмір-фаилів-для-webdav-завантаження" aria-label="Permalink to &quot;Розмір файлів для WebDAV-завантаження&quot;">​</a></h2><p>WebDAV-клієнти не використовують browser upload page&#39;s large-file chunking flow. Для файлів, більших за рекомендовані нижче ліміти, використовуйте вебсторінку завантаження.</p><table tabindex="0"><thead><tr><th>Default Upload Channel</th><th style="text-align:right;">Рекомендований ліміт одного файлу для WebDAV</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>Hugging Face</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',61)])])}const D=i(n,[["render",o]]);export{m as __pageData,D as default};
